parameters.jsCode:
const d = $input.first().json;
const now = new Date();
const due = (days) => {
  const dt = new Date(now);
  dt.setDate(dt.getDate() + days);
  return dt.toISOString();
};
return [{
  json: {
    client_name: d.client_name,
    client_email: d.client_email,
    company: d.company,
    service: d.service,
    start_date: d.start_date || now.toISOString().split('T')[0],
    tasks: [
      { task: 'Enviar email de bienvenida + brochure', due: due(1), priority: 'high' },
      { task: 'Agendar llamada de descubierta (30 min)', due: due(3), priority: 'high' },
      { task: 'Enviar formulario de intake', due: due(3), priority: 'medium' },
      { task: 'Crear carpeta en Drive + compartir', due: due(2), priority: 'medium' },
      { task: 'Preparar propuesta detallada', due: due(7), priority: 'medium' },
      { task: 'Generar invoice de setup si aplica', due: due(5), priority: 'medium' },
      { task: 'Primer entregable según servicio', due: due(14), priority: 'high' },
      { task: 'Revisión 30 días + feedback', due: due(30), priority: 'low' }
    ]
  }
}];

